import { ipcMain, dialog, BrowserWindow } from 'electron';
import { z } from 'zod';
import fs from 'fs';
import path from 'path';
import {
  IPC_CHANNELS,
  CreateSecretCollectionSchema,
  UpdateSecretCollectionSchema,
  SecretCollectionIdSchema,
  ImportEnvFileSchema,
} from './types';
import { secretVaultService } from '../services/SecretVaultService';

export function registerSecretVaultHandlers() {
  // Get all collections (metadata only)
  ipcMain.handle(IPC_CHANNELS.SECRETS_GET_ALL, async () => {
    try {
      const collections = secretVaultService.getAllCollections();
      return { success: true, data: collections };
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Failed to get collections',
      };
    }
  });

  // Get collection by ID with decrypted secrets
  ipcMain.handle(IPC_CHANNELS.SECRETS_GET_BY_ID, async (_event, input) => {
    try {
      const { id } = SecretCollectionIdSchema.parse(input);
      const collection = await secretVaultService.getCollectionSecrets(id);
      if (!collection) return { success: false, error: 'Collection not found' };
      return { success: true, data: collection };
    } catch (error) {
      if (error instanceof z.ZodError) {
        return { success: false, error: error.issues[0]?.message || 'Validation failed' };
      }
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Failed to get collection',
      };
    }
  });

  // Get secrets as Record<string, string> for import into env editors
  ipcMain.handle(IPC_CHANNELS.SECRETS_GET_SECRETS, async (_event, input) => {
    try {
      const { id } = SecretCollectionIdSchema.parse(input);
      const secrets = await secretVaultService.getSecretsAsRecord(id);
      if (!secrets) return { success: false, error: 'Collection not found' };
      return { success: true, data: secrets };
    } catch (error) {
      if (error instanceof z.ZodError) {
        return { success: false, error: error.issues[0]?.message || 'Validation failed' };
      }
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Failed to get secrets',
      };
    }
  });

  // Create collection
  ipcMain.handle(IPC_CHANNELS.SECRETS_CREATE, async (_event, input) => {
    try {
      const parsed = CreateSecretCollectionSchema.parse(input);
      const collection = await secretVaultService.createCollection(parsed);
      return { success: true, data: collection };
    } catch (error) {
      if (error instanceof z.ZodError) {
        return { success: false, error: error.issues[0]?.message || 'Validation failed' };
      }
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Failed to create collection',
      };
    }
  });

  // Update collection
  ipcMain.handle(IPC_CHANNELS.SECRETS_UPDATE, async (_event, input) => {
    try {
      const { id, updates } = UpdateSecretCollectionSchema.parse(input);
      await secretVaultService.updateCollection(id, updates);
      return { success: true };
    } catch (error) {
      if (error instanceof z.ZodError) {
        return { success: false, error: error.issues[0]?.message || 'Validation failed' };
      }
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Failed to update collection',
      };
    }
  });

  // Delete collection
  ipcMain.handle(IPC_CHANNELS.SECRETS_DELETE, async (_event, input) => {
    try {
      const { id } = SecretCollectionIdSchema.parse(input);
      secretVaultService.deleteCollection(id);
      return { success: true };
    } catch (error) {
      if (error instanceof z.ZodError) {
        return { success: false, error: error.issues[0]?.message || 'Validation failed' };
      }
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Failed to delete collection',
      };
    }
  });

  // Import from .env file content
  ipcMain.handle(IPC_CHANNELS.SECRETS_IMPORT_ENV, async (_event, input) => {
    try {
      const { name, description, tags, envContent } = ImportEnvFileSchema.parse(input);
      const secrets = secretVaultService.parseEnvContent(envContent);
      const collection = await secretVaultService.createCollection({
        name,
        description,
        tags,
        secrets,
      });
      return { success: true, data: collection };
    } catch (error) {
      if (error instanceof z.ZodError) {
        return { success: false, error: error.issues[0]?.message || 'Validation failed' };
      }
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Failed to import env file',
      };
    }
  });

  // Select .env files from filesystem (native dialog)
  ipcMain.handle(IPC_CHANNELS.SECRETS_SELECT_ENV_FILES, async () => {
    try {
      const parentWindow =
        BrowserWindow.getFocusedWindow() || BrowserWindow.getAllWindows()[0] || null;
      const dialogOpts: Electron.OpenDialogOptions = {
        title: 'Select .env Files',
        properties: ['openFile', 'multiSelections'],
        filters: [
          { name: 'Environment Files', extensions: ['env'] },
          { name: 'All Files', extensions: ['*'] },
        ],
      };

      const result = parentWindow
        ? await dialog.showOpenDialog(parentWindow, dialogOpts)
        : await dialog.showOpenDialog(dialogOpts);

      if (result.canceled || result.filePaths.length === 0) {
        return { success: true, data: [] };
      }

      const files = result.filePaths.map((filePath) => ({
        name: path.basename(filePath, path.extname(filePath)),
        content: fs.readFileSync(filePath, 'utf-8'),
      }));

      return { success: true, data: files };
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Failed to select files',
      };
    }
  });

  // Export collection as .env file
  ipcMain.handle(IPC_CHANNELS.SECRETS_EXPORT_ENV, async (_event, input) => {
    try {
      const { id } = SecretCollectionIdSchema.parse(input);
      const secrets = await secretVaultService.getSecretsAsRecord(id);
      if (!secrets) return { success: false, error: 'Collection not found' };

      const envContent = Object.entries(secrets)
        .map(([k, v]) => `${k}=${v}`)
        .join('\n');

      const parentWindow =
        BrowserWindow.getFocusedWindow() || BrowserWindow.getAllWindows()[0] || null;
      const dialogOpts: Electron.SaveDialogOptions = {
        title: 'Export .env File',
        defaultPath: 'exported.env',
        filters: [{ name: 'Environment Files', extensions: ['env'] }],
      };

      const result = parentWindow
        ? await dialog.showSaveDialog(parentWindow, dialogOpts)
        : await dialog.showSaveDialog(dialogOpts);

      if (result.canceled || !result.filePath) {
        return { success: true, data: '' };
      }

      fs.writeFileSync(result.filePath, envContent, 'utf-8');
      return { success: true, data: result.filePath };
    } catch (error) {
      if (error instanceof z.ZodError) {
        return { success: false, error: error.issues[0]?.message || 'Validation failed' };
      }
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Failed to export',
      };
    }
  });
}
